sp_widget.client_script:
function widgetClientController($scope, $location, spUtil, $rootScope, amb, $http, spAriaUtil, $timeout, spModal) {
    // Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
    // Script Continued Below
    //------------------------------------------------------------------------------------------------------------------------
    var c = this;
    c.refresh = function() {
        //KT: STRY0065140
        if (c.data.page_id != "discovertasker_processtemplatedetails")
            c.server.update();
    };
    /*
    $("td:contains(true)").css("color","green");
    $("td:contains(false)").css("color","red");
    */

    /*
     * options:
     * hide_footer (bool) = true to remove the data table footer contents
     * hide_header (bool) = true to remove the data table header contents
     * show_new (bool) = true to show the "New" record button
     * show_keywords (bool) = true to show the keyword search field
     * table (string) = the table name to query
     * filter (string) = the encoded query
     * o (string) = the order by column
     * d (string) = The order by direction: asc or desc
     * p (int) = the page to jump to
     * fields (string) = comma seperated list of fields that become the list columns
     * view (string) = the default view to load for columns, overrides fields
     */

    if (c.data.fromModal === true)
        c.refresh();

    // Sets the diffrent exporting data types that this table is capable of producing
    $scope.exportTypes = [{
        label: 'PDF',
        value: 'PDF'
    }, {
        label: 'Excel',
        value: 'EXCEL'
    }, {
        label: 'CSV',
        value: 'CSV'
    }];
    var keys = ['table', 'filter', 'p', 'o', 'd'];

    // Sets an eventNames data object to be used in diffrent functions based on events
    var eventNames = {
        click: 'data_table.click',
        setFilter: 'data_table.setFilter',
        setKeywords: 'data_table.setKeywords'
    };

    // Listens to a declareActiveTab event to define the active tab in the data table
    $rootScope.$on('declareActiveTab', function(event, activeTab) {
        c.activeTab = activeTab;
    });

    $scope.goTasker = function(table, item) {
        var parms = {};
        parms.table = table;
        parms.sys_id = item.sys_id;
        parms.record = item;
        $scope.ignoreLocationChange = true;
        for (var x in c.data.list) {
            c.data.list[x].selected = false;
        }
        item.selected = true;

        $rootScope.$emit('dataTableClick', item);
        var currentPageId = $location.search()['id'];
        //KT: STRY0065140
        if ((currentPageId != ("discovertasker_processtemplatelist")) && (currentPageId != "discovertasker_processtemplatedetails")) {
					// STRY0101803 added this to use Tasker Data Table for styling on the drill down page
					if (currentPageId == "discovertasker_detailsdrilldown") {				
						var p = $scope.data.page_id || 'form';
						var s = {id: p, table: parms.table, sys_id: parms.sys_id, view: $scope.data.view};
						$rootScope.$broadcast('$sp.list.click', s);
					}else {
            $scope.$emit(eventNames.click, parms);
					}					
        }

    };

    //------------------------------------------------------------------------------------------------------------------------
    // CUSTOM: MODAL
    //------------------------------------------------------------------------------------------------------------------------
    $scope.openModal = function(item) {

        for (var x in c.data.items) {
            c.data.items[x].selected = false;
        }

        item.selected = true;
        $scope.data.selected = item;

        /* opens the platform form in a modal for this table */
        spModal.open({
            title: $scope.data.table_label,
            backdrop: 'static',
            widget: 'discovertasker-formtab',
            //STRY0065050: Get view from scope
            widgetInput: {
                table: $scope.data.table,
                sys_id: item.sys_id,
                view: $scope.data.view,
                isModal: true
            },
            size: 'lg',
            buttons: []

        }).then(function() {
            /* update model after return from modal */
            c.server.update();
        });
        $("td").removeClass("selected");
    };

    $scope.openModalProcessTemplate = function(item) {

        for (var x in c.data.items) {
            c.data.items[x].selected = false;
        }
        item.selected = true;
        $scope.data.selected = item;
        /* opens the platform form in a modal for this table */
        spModal.open({
            title: "Template Information",
            backdrop: 'static',
            widget: 'discovertasker-formtab',
            widgetInput: {
                table: $scope.data.table,
                sys_id: item.sys_id,
                isModal: true
            },
            size: 'lg',
            buttons: []

        }).then(function() {
            /* update model after return from modal */
            c.server.update();
        });
    };
    function confirmAndSave() {
			// If the form is dirty, ask the user if they would like to save the record
			var continueOpen = false;
			var fMsg = '';
			var serializeChanges = g_form.serialize(true);
			if(serializeChanges.length>0){
				var changeFieldList = [];
				for (var field in serializeChanges) {
					changeFieldList.push(serializeChanges[field].label.trim());
				}
				fMsg = changeFieldList.join(', ');

				spModal.confirm("${Tasker - Modal Save Changes Message}  "+ fMsg).then(function(confirmed) {
						g_form.save();
						continueOpen = true;
				});
			}else{
				continueOpen = true;
			}
			return continueOpen;
    }

		function open_New_Modal(table, title, view, query) {
			var formQuery = query;
			spModal.open({
				title: title,
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: {
					table: table,
					sys_id: "-1",
					view: view,
					query: formQuery,
					// DFCT0010635
					omitHeader: 'true',
					// STRY0040294 - added isModal - added closing of open modal
					isModal: true //,
				},
				size: 'lg',
				buttons: []
			});
		}	

    $scope.newRecord = function() {
			// check for save or cancel
			if(!confirmAndSave)
				return false;
			// open in modal if set
			if (c.data.open_new_in_modal){
				open_New_Modal(c.data.table, 'New ' + c.data.table_label, $scope.data.view, $scope.data.filter);
				return;
			}
        var parms = {
            id: 'form',
            table: $scope.data.table,
            view: $scope.data.view,
            sys_id: '-1'
        };
        if ($scope.data.filter != '')
            parms.query = $scope.data.filter;

        $location.search(parms);
    };	
    //------------------------------------------------------------------------------------------------------------------------
    // END CUSTOM
    //------------------------------------------------------------------------------------------------------------------------

    $scope.go = function(table, item) {
        var parms = {};
        parms.table = table;
        parms.sys_id = item.sys_id;
        parms.record = item;
        $scope.ignoreLocationChange = true;
        for (var x in c.data.list) {
            c.data.list[x].selected = false;
        }
        item.selected = true;
        $scope.$emit(eventNames.click, parms);
    };

    function recoverStateFromUrl() {
        $scope.data.fields = [];
        var s = $location.search();

        for (var x in keys) {
            if (s[keys[x]]) {
                $scope.data[keys[x]] = s[keys[x]];
            }
        }
        $scope.server.update().then(function(data) {
            if (s.sys_id) {
                for (var x in data.list) {
                    if (data.list[x].sys_id == s.sys_id) {
                        $scope.go(s.table, data.list[x]);
                    }
                }
            }
        });
    }

    if ($scope.options.fromUrl) {
        var origSearch = $location.search();
        $scope.$on('$locationChangeSuccess', function(e) {
            var s = $location.search();
            if (origSearch.id !== s.id)
                return;

            if ($scope.ignoreLocationChange) {
                $scope.ignoreLocationChange = false;
                return;
            }

            // Helps to recover state when using the browser's back button
            recoverStateFromUrl();
        });
    }


    $scope.getNumber = function(num) {
        return new Array(num);
    };

    $scope.mathMin = function(v1, v2) {
        return Math.min(v1, v2);
    };

    function getData(updateUrl) {
        var f = $scope.data;
        spUtil.update($scope).then(function(data) {
            f.view = data.view;
            if ($scope.options.fromUrl && updateUrl)
                setPermalink(f.table, f.filter, f.o, f.d, f.p);

            if ($scope.options.show_breadcrumbs && data.filterBreadcrumbs)
                $scope.$broadcast('widget-filter-breadcrumbs.setBreadcrumbs', data.filterBreadcrumbs.data, data.filter);

            initRecordWatcher(f.table, f.filter);
        });
    }

    function setPermalink(table, filter, orderBy, orderDirection, page) {
        $scope.ignoreLocationChange = true;
        var search = $location.search();
        angular.extend(search, {
            spa: 1,
            table: table,
            filter: filter,
            p: page,
            o: orderBy,
            d: orderDirection
        });
        $location.search(search);
    }

    var watcher;

    function initRecordWatcher(table, filter) {
        if (watcher)
            watcher.unsubscribe();

        if (table && filter) {
            // STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
            var params = {};
            var watcherChannel = amb.getChannelRW(table, filter);
            amb.connect();
            watcher = watcherChannel.subscribe(function(message) {
                if (!message.data)
                    return;
                switch (message.data.action) {
                    case "change":
                        updateRowFromRW(message);
                        break;
					case "exit":
						// A record was removed
						// STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
						// pass the table back to the form widget for the related list
						params.table = c.data.table;
						// pass the filter back to the form widget for the related list in case there are 2 related lists of the same table
						params.filter = c.data.filter;
						// 2.7.0 | 2021-05-21 | mmcc | STRY0099596 Record Watcher on Template Count not Updating; emit sends rowCount in params, no need for .Deleted or .Added
						// $rootScope.$broadcast('sp.DiscoverListItem.Deleted', params);
						// spUtil.update($scope);
						spUtil.update($scope).then(function() {
							params.rowCount = $scope.data.row_count || 0;
							$scope.$emit('sp.DiscoverListItem', params);
						});
						break;
					case "entry":
						// A record was added
						// STRY0093948 - when a row is added, broadcast event to Tab Form with Tabs to update the count
						// pass the table back to the form widget for the related list
						params.table = c.data.table;
						// pass the filter back to the form widget for the related list in case there are 2 related lists of the same table
						params.filter = c.data.filter;
						// 2.7.0 | 2021-05-21 | mmcc | STRY0099596 Record Watcher on Template Count not Updating; emit sends rowCount in params, no need for .Deleted or .Added
						// $rootScope.$broadcast('sp.DiscoverListItem.Added', params);
						//spUtil.update($scope);
						spUtil.update($scope).then(function() {
							params.rowCount = $scope.data.row_count || 0;
							$scope.$emit('sp.DiscoverListItem', params);
						});
						break;
                    default:
                        spUtil.update($scope);
                        break;
                }
            });
        }
    }

    function updateRowFromRW(message) {
        if (message.data && message.data.sys_id && $scope.data.list) {
            var row, field;
            for (var i = 0; i < $scope.data.list.length; i++) {

                row = $scope.data.list[i];
                if (row.sys_id == message.data.sys_id) {
                    var fields = Object.getOwnPropertyNames(message.data.record);
                    for (var f in fields) {
                        field = fields[f];
                        if (typeof row[field] !== 'undefined') {
                            row[field].display_value = message.data.record[field].display_value;
                        }
                    }
                }
            }
        }
    }

    $scope.$on('$destroy', function() {
        if (watcher)
            watcher.unsubscribe();
    });

    $scope.setPageNum = function(num) {
        $scope.data.p = num;
        getData(true);
        $timeout(function() {
            $scope.focusOnTableHeader();
        });
    };

    $scope.setOrderBy = function(field) {
        var d = "asc";
        if ($scope.data.o == field) {
            if ($scope.data.d == "asc")
                d = "desc";
            else
                d = "asc";
        }

        if (d === "asc") {
            spAriaUtil.sendLiveMessage($scope.data.msg.sortingByAsc);
        } else if (d === "desc") {
            spAriaUtil.sendLiveMessage($scope.data.msg.sortingByDesc);
        }

        $scope.data.o = field;
        $scope.data.d = d;
        $scope.setSearch(true);
    };

    $scope.setSearch = function(updateUrl) {
        $scope.data.p = 1;
        getData(updateUrl);
    };

    $scope.$on(eventNames.setFilter, function(e, newFilter) {
        $scope.data.filter = newFilter;
        $scope.setSearch(false);
    });

    $scope.$on(eventNames.setKeywords, function(e, keywords) {
        $scope.data.keywords = keywords;
        $scope.setSearch(false);
    });

    $scope.$on('widget-filter-breadcrumbs.queryModified', function(e, newFilter) {
        $scope.data.filter = newFilter;
				// DFCT0010709
				$scope.data.breadcrumb_change=true;
        $scope.setSearch(true);
    });

    $scope.rowsWerePruned = function() {
        if (!$scope.data.list)
            return;

        $scope.rowsPruned = $scope.mathMin($scope.data.window_end, $scope.data.row_count) - $scope.data.window_start - $scope.data.list.length;
        return $scope.rowsPruned > 0;
    };

    $scope.showFilter = function() {
        return !$scope.data.list.length && !$scope.data.num_pages && !$scope.data.invalid_table && !$scope.loadingData;
    };

    c.appendQuery = function(query) {
        if ($scope.data.filter.length > 1)
            $scope.data.filter += '^';
        $scope.data.filter += query;
        $scope.setSearch();

    };

    // Makes Widget Async
    var title = $scope.data.title;
    if ($scope.options.use_instance_title == 'true')
        title = $scope.options.title;

		// DFCT0010439 - "My Office" button on Organizational Hierarchy is displaying the wrong table/information
		if($scope.data.table==undefined){
			$scope.data = $scope.options;	
		}

    //jslog($scope.data.filter)
    $scope.loadingData = true;
    $scope.server.update().then(function() {
        //if ($scope.data.newButtonUnsupported)
        //jslog("Service Portal: New button not supported for sys_attachment list");
        $scope.loadingData = false;
        $scope.data.title = title;
        initRecordWatcher($scope.data.table, $scope.data.filter);
    });

    function parseQuery(table, queryString) {
        return $http.post('/api/now/sp/parsequery/' + table, queryString).then(function(response) {
            return response.data.result;
        });
    }

    c.createQueryTerm = function(table, field, sys_id, operator) {
        return $http.get('/api/now/sp/getInOutQueryTerm', {
            params: {
                table: table,
                sys_id: sys_id,
                field: field,
                operator: operator
            }
        }).then(function(response) {
            if (response && response.data && response.data.result)
                return response.data.result.parts;
        });
    };

    c.showMatching = function(field, newTerm) {
        var queryString = $scope.data.filter;
        var eq = "";
        parseQuery($scope.data.table, queryString).then(function(oldTerms) {
            for (var i = 0; i < oldTerms.length; i++) {
                var term = oldTerms[i];
                if (isSameField(newTerm, term))
                    continue;

                if (eq.length)
                    eq += '^';

                eq += getEncodedTerm(term);
            }
            if (eq.length)
                eq += '^';
            eq += getEncodedTerm(newTerm);

            $scope.data.filter = eq;
            $scope.setSearch();
        });
    };

    c.filterOut = function(field, newTerm) {
        var eq = $scope.data.filter;
        if (eq.length)
            eq += '^';

        eq += getEncodedTerm(newTerm);
        $scope.data.filter = eq;
        $scope.setSearch();
    };

    function isSameField(t1, t2) {
        if ('left' in t1 && 'left' in t2)
            return t1.left.field === t2.left.field;
        else if ('left' in t1)
            return t1.left.field === t2.field;
        else if ('left' in t2)
            return t1.field === t2.left.field;
        return t1.field === t2.field;
    }

    function getEncodedTerm(term) {
        var eq;
        if (term.left) {
            eq = getEncodedTerm(term.left);
            eq += '^OR';
            eq += getEncodedTerm(term.right);
        } else {
            eq = term.field;
            eq += term.operator;
            eq += term.value;
        }
        return eq;

    }


}

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.02.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------

//------------------------------------------------------------------------------------------------------------------------
// 2.5.3 | 10.09.2020 | KT | UI  | STRY0083485: Console log error: Status field
//------------------------------------------------------------------------------------------------------------------------


//------------------------------------------------------------------------------------------------------------------------
// STATES
//------------------------------------------------------------------------------------------------------------------------
.Waiting {
    background-color: $state-waiting-bg;
		color: $state-waiting-text;
}

.Unassigned {
  	background-color: $state-unassigned-bg;
  	color: $state-unassigned-text; 
}

.Assigned {
  	background-color: $state-assigned-bg;
		color: $state-assigned-text;
} 

.Accepted {
  	background-color: $state-accepted-bg;
		color: $state-accepted-text;
}

.Rejected {
 		background-color: $state-rejected-bg;
		color: $state-rejected-text;
}

.Work.Scheduled {
  	background-color: $state-workscheduled-bg;
		color: $state-workscheduled-text;
}

.Work.in.Progress {
  	background-color: $state-workinprogress-bg;
		color: $state-workinprogress-text;
}

.In.Review {
  	background-color: $state-inreview-bg; 
		color: $state-inreview-text;
}

.Rework {
  	background-color: $state-rework-bg;
		color: $state-rework-text;
}

.Completed {
  	background-color: $state-completed-bg;
		color: $state-completed-text;
}
/* 2.6.0 | 2021-04-23 | mmcc | STRY0090503 Closed Incomplete is missing the color */
.Closed.Incomplete {
  	background-color: $state-closedincomplete-bg;
		color: $state-closedincomplete-text;
}

.Cancelled {
  	background-color: $state-cancelled-bg;
		color: $state-cancelled-text;
}

//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.08.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.3 | 10.09.2020 | KT | UI  | STRY0083485: Console log error: Status field
//------------------------------------------------------------------------------------------------------------------------

//------------------------------------------------------------------------------------------------------------------------
// STATUS
//------------------------------------------------------------------------------------------------------------------------

.Projected.on.time {
  background-color:  $success;
  color: $brand-success-text;
}

.Warning {
  background-color:  $warning;
  color: $brand-warning-text;
}

.Critical {
  background-color:  $danger;
  color: $brand-danger-text;
}


//------------------------------------------------------------------------------------------------------------------------
// GENERAL
//------------------------------------------------------------------------------------------------------------------------
.blocked{
 display: block;
}

.panel-heading {
  padding-left: 8px;
}

thead {
  border-bottom: 1px solid #ddd;
}

table {
  margin-bottom: 0;
}

.table > thead > tr > th {
  border: 1px solid #ddd;
  cursor: pointer;
  vertical-align: middle;

  &:nth-child(2) {
    border-left: none;
  }

  &:last-child {
    border-right: none;
  }
}

th i {
  display: inline-block;
  margin-left: 5px;
  color: #A0A0A0;
}

th .disabled{
  color:#ddd;
}

.th-title {
  display: inline-block;
  color: $primary;
}

.panel-body {
  overflow: auto;
  padding: 0px;
}

.selected {
  color: $taskerdatatable-selected-row-text;
  background-color: $taskerdatatable-selected-row-bg;
  border-color: 1px solid #fff;
}

tbody tr:last-child {
  border-bottom: none;
}

.pruned-msg {
  padding-bottom: 10px;
  padding-left: 4px;
  text-align: center;
}

.pruned-msg-filter-pad {
  padding-top:8px;
}

.filter-breadcrumbs {
  border-bottom: 1px solid #ddd;
  padding-top: 3px;
}

.dropdown-toggle {
  background: none;
  padding: 0 0 4px 0;
}

sp_widget.link:
function (scope, element, attrs, ctrl){
	var $ul, $contextMenu;

	scope.focusOnTableHeader = function() {
		element.find(".data-table-title").attr("tabindex", "-1").focus();
	};

	element.on('contextmenu', function(e){
		if (e.ctrlKey)
			return; // ctrlKey is for the debug menu, not this menu

		var rowScope = angular.element(e.target).scope();
		var field, item, fieldVal;

		// Context Menu for tbody
		if (angular.isDefined(rowScope.field) && angular.isDefined(rowScope.item)){
			e.preventDefault();
			field = rowScope.field;
			item = rowScope.item;
			fieldVal = item[field].value;

			var items = [
			['${Show Matching}', function(){
				ctrl.createQueryTerm(scope.data.table, field, item.sys_id, '=').then(function(term){
					ctrl.showMatching(field, term);
				});
			}],
			['${Filter Out}', function(){
				ctrl.createQueryTerm(scope.data.table, field, item.sys_id, '!=').then(function(term){
					ctrl.filterOut(field, term);
				});
			}]
			];

			renderContextMenu(items);
			setContextMenuPosition(e);
		}
	});

	function renderContextMenu(items){
		var scrollHeight = $('body').get(0).scrollHeight;
		$contextMenu = angular.element('<div>', {'class': 'dropdown clearfix context-dropdown open'});

			$contextMenu.on('click', function (e) {
				if ($(e.target).hasClass('dropdown')) {
					_clearContextMenus(event);
				}
			});
			$contextMenu.on('contextmenu', function (event) {
				event.preventDefault();
				_clearContextMenus(event);
			});

			$contextMenu.css({
				position: 'absolute',
				top: 0,
				height: scrollHeight,
				left: 0,
				right: 0,
				zIndex: 9999
			});

			$('body').append($contextMenu);

			$ul = angular.element('<ul>', {
				'class': 'dropdown-menu',
				'role': 'menu'
			});
			renderItems();
			$contextMenu.append($ul);

			function renderItems(){
				angular.forEach(items, function (item) {
					var $li = angular.element('<li>');

					if (item === null) {
						$li.addClass('divider');
					} else {
						var $a = angular.element('<a>');
						$a.attr({tabindex: '-1', href:'#'});
							$a.text(item[0]);
							$li.append($a);
							$li.on('click', function (e) {
								e.preventDefault();
								scope.$apply(function () {
									_clearContextMenus(e);
									item[1].call(item, item);
								});
							});
						}

						$ul.append($li);
					});
				}
			}

			function _clearContextMenus(event){
				if (!event){
					return;
				}

				angular.element(event.currentTarget).removeClass('context');

				var els = angular.element(".context-dropdown");
				angular.forEach(els, function(el){
					angular.element(el).remove();
				});
			}

			var contextMenuItemHeight = 0;
			function setContextMenuPosition(event){
				if (contextMenuItemHeight === 0)
					contextMenuItemHeight = $ul.children(0).height();

				// Why not just call .width() and .height() on the container? Because those calculations cause browsers to reflow
				// that can cause IE10 to take 200ms to render a context menu.
				var cmWidth = 150;
				var cmHeight = contextMenuItemHeight * $ul.children().length;
				var startX = event.pageX + cmWidth >= window.innerWidth ? event.pageX - cmWidth : event.pageX;
				var startY = event.pageY + cmHeight >= window.innerHeight ? event.pageY - cmHeight : event.pageY;

				$ul.css({
					display: 'block',
					position: 'absolute',
					left: startX,
					top: startY,
					'min-width': cmWidth
				});
			}
		}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
// WIDGET BASE: DATA TABLE
//------------------------------------------------------------------------------------------------------------------------
//
// 2.6.0 | 2021-03-25 | mmcc | STRY0096103 Tree Level Print Report: Activity Log; HTML changed
// 2.6.0 | 2021-04-23 | mmcc | STRY0090503 Closed Incomplete is missing the color in the filter widget on the Modern 
//                                         Portal page and Chevron color is missing on the task form.
//                                         Change made in CSS only.
// 2.7.0 | 2021-05-21 | raj  | STRY0101546 - EXP - Tasker Email change to asynchronous email - UPDATE status asynchronously
//                                         Change made in HTML only.
// 2.7.0 | 2021-05-21 | mmcc | STRY0099596 Record Watcher on Template Count not Updating
// 											emit sends rowCount in params, no need for .Deleted or .Added
//                                         Change made in Client controller only.
// 2.7.0 | 2021-07-21 | raj | STRY0106159 Platform view is accessible from context list menus on Existing Tasks forms
//                                         Change made in Server Script, HTML only.
// 2.7.0 | 2021-08-17 | raj | DFCT0010439 - "My Office" button on Organizational Hierarchy is displaying the wrong table/information
//                                         Change made in Client Script, only.
// 2.7.0 | 2021-09-01 | raj  | STRY0108599 - Removed the full screen from this widget for Organizational Hierarchy.
//																					HTML - was looking at options.show_new which won't pick up when the widget is opened in modal
//																					Server - updated the setting of the variables as they weren't pickup up input and options
// 2.7.0 | 2021-11-14 | raj  | DFCT0010635 - Remove "Context Menu" from all "New" forms in the Tasker system
//											Changes in Client script.
// 2.7.1 | 2021-12-17 | raj  | DFCT0010709 - "Modern Portal" filters does NOT allow user to remove the last condition
//                                         Changes made in Server Script and Client Controller
// 2.7.1 | 2021-12-17 | raj  | DFCT0010593 "Tasker Number" and "Task Name" fields are were blank on "Excel Export" from DTLV for non-admins.  
//                                         Changes made in Server Script

//------------------------------------------------------------------------------------------------------------------------

(function() {
    if (!input) // asynch load list
        return;

    data.msg = {};
    data.msg.sortingByAsc = gs.getMessage("Sorting by ascending");
    data.msg.sortingByDesc = gs.getMessage("Sorting by descending");

    data.title = options.title || input.title;
    data.fromModal = input.fromModal || '';

    /*
     * data.table = the table
     * data.p = the current page starting at 1
     * data.o = the order by column
     * data.d = the order by direction
     * data.keywords = the keyword search term
     * data.list = the table data as an array
     * data.invalid_table = true if table is invalid or if data was not succesfully fetched
     * data.table_label = the table's display name. e.g. Incident
     * data.table_plural = the table's plural display name. e.g. Incidents
     * data.fields = a comma delimited list of field names to show in the data table
     * data.column_labels = a map of field name -> display name
     * data.window_size = the number of rows to show
     * data.filter = the encoded query
     */
    // copy to data[name] from input[name] || option[name]
    optCopy(['table', 'p', 'o', 'd', 'filter', 'filterACLs', 'fields', 'keywords', 'view']);
    optCopy(['relationship_id', 'apply_to', 'apply_to_sys_id', 'window_size']);

    data.showInactiveProcess = input.showInactiveProcess;
    //data.view = data.view || 'mobile';
    //KT - RLS - STRY0065050: 04/01/2020: Added
		// 2.7.0 | 2021-07-24 - added $sp.getParameter() on the calls to pull from URL when everything else is blank
		// 2.7.1 | 2021-12-20 - DFCT0010593 - the change above caused overrode input passed in as the view
    data.view = data.view || $sp.getParameter("v") || $sp.getParameter("view") || data.view; // SP default from data.view
		data.table = data.table || $sp.getValue('table') || $sp.getParameter('table');
		// DFCT0010709 - when user cleared the filter using breadcrumb, the data.filter would be blank.
		//               when the filter was blank, it would reload the filter from the Option Copy call below resetting the fitler to the value passed in the options
		//               this prevented the user from completely clearing the filter
		//               a new variable was added in the client script when the filter is changed from the breadcrumb
		//               this variable is checked in the if statement below to delete the filter from optionis instead of resetting to the filter passed in options
		if(input.breadcrumb_change==true){
				data.filter = input.filter;
		} else {
			data.filter = data.filter || $sp.getValue('filter') || $sp.getParameter('filter');
		}


    data.keywords = data.keywords || $sp.getValue('keywords') || $sp.getParameter('keywords');
    data.p = data.p || $sp.getValue('p') || $sp.getParameter('p') || 1;
    data.p = parseInt(data.p);
    data.o = data.o || $sp.getValue('o') || $sp.getValue('order_by') || $sp.getParameter('order_by') || $sp.getParameter('o');
    data.d = data.d || $sp.getValue('d') || $sp.getValue('order_direction') || $sp.getParameter('order_direction') || $sp.getParameter('d');

    data.page_index = data.p - 1;
		// STRY0108599
    data.show_new = (input.show_new == true || input.show_new == "true" ||
        options.show_new == true || options.show_new == "true");
		data.open_new_in_modal = (input.open_new_in_modal == true || input.open_new_in_modal == "true" || options.open_new_in_modal == true || options.open_new_in_modal == "true"); 
    data.open_row_details_in_modal = (input.open_row_details_in_modal == true || input.open_row_details_in_modal == "true" || options.open_row_details_in_modal == true || options.open_row_details_in_modal == "true"); //New feature added. KTorres
    data.enable_filter = (input.enable_filter == true || input.enable_filter == "true" ||
        options.enable_filter == true || options.enable_filter == "true");

		// 2.7.0 | 2021-07-24 - move after the $sp pulls values from the URL
    if (!data.table) {
        data.invalid_table = true;
        data.table_label = "";
        return;
    }
		// 2.7.0 | 2021-07-21 | raj | STRY0106159 Platform view is accessible from context list menus on Existing Tasks forms
		data.hasRoleTaskerUser = gs.hasRole('x_153465_discovert.tasker_user');

    if (!data.fields) {
        if (data.view)
            data.fields = $sp.getListColumns(data.table, data.view);
        else
            data.fields = $sp.getListColumns(data.table);
    }

    var windowSize = data.window_size || $sp.getValue('maximum_entries') || 20;
    windowSize = parseInt(windowSize);
    if (isNaN(windowSize) || windowSize < 1)
        windowSize = 20;
    data.window_size = windowSize;

    var gr;
    ///if (gs.getProperty("glide.security.ui.filter") == "true" || GlideTableDescriptor.get(data.table).getED().hasAttribute("glide.security.ui.filter")) { // From Global. KTorres
    if (gs.getProperty("glide.security.ui.filter") == "true") {
        gr = new FilteredGlideRecord(data.table);
        gr.applyRowSecurity();
    } else
        gr = new GlideRecordSecure(data.table);
    if (!gr.isValid()) {
        data.invalid_table = true;
        data.table_label = data.table;
        return;
    }

    data.canCreate = gr.canCreate();
    data.newButtonUnsupported = data.table == "sys_attachment";
    data.table_label = gr.getLabel();
    //data.table_plural = gr.getPlural(); // From Global. KTorres
    data.table_plural = input.title || data.table_label;

    if (data.filter) {
        if (data.filterACLs)
            gr = $sp.addQueryString(gr, data.filter);
        else
            gr.addEncodedQuery(data.filter);
    }

    if (data.keywords) {
        gr.addQuery('123TEXTQUERY321', data.keywords);
        data.keywords = null;
    }
    data.filter = gr.getEncodedQuery();

    if (data.relationship_id) {
        var rel = GlideRelationship.get(data.relationship_id);
        var target = new GlideRecord(data.table);
        var applyTo = new GlideRecord(data.apply_to);
        applyTo.get("sys_id", data.apply_to_sys_id);
        rel.queryWith(applyTo, target); // put the relationship query into target
        gr.addEncodedQuery(target.getEncodedQuery()); // get the query the relationship made for us
    }

		// 2.7.0 | 2021-07-21 | raj | STRY0106159 Platform view is accessible from context list menus on Existing Tasks forms
		data.orderByParameter = '';
    if (data.o) {
        if (data.d == "asc"){
					gr.orderBy(data.o);
					data.orderByParameter = '&ORDERBY' + data.o;
				} else {
					gr.orderByDesc(data.o);
					data.orderByParameter = '&ORDERBYDESC' + data.o;
				}
    }
    // only show active process ----------------------
    if (data.table == 'x_153465_discovert_discover_routing_template' && data.showInactiveProcess != true) {
        gr.addQuery('u_active', true);
    }

    data.window_start = data.page_index * data.window_size;
    data.window_end = (data.page_index + 1) * data.window_size;
    gr.chooseWindow(data.window_start, data.window_end);
    gr._query();

    data.row_count = gr.getRowCount();
    data.num_pages = Math.ceil(data.row_count / data.window_size);
    data.column_labels = {};
    data.fields_array = data.fields.split(',');

    // use GlideRecord to get field labels vs. GlideRecordSecure
    var grForLabels = new GlideRecord(data.table);
    for (var i in data.fields_array) {
        var field = data.fields_array[i];
        var ge = grForLabels.getElement(field);

        //---------------------------------------------
        //STRY0071963: Servcienow Server JavaScript error getLabel in object null.
        /*if (ge == null)
        	continue;

        data.column_labels[field] = ge.getLabel();
        */
        try {
            if (ge == null)
                continue;

            data.column_labels[field] = ge.getLabel();
        } catch (ex) {
            var message = ex.message;
            gs.error("Tasker error in Tasker Data Table Widget - field : " + message + " | field: " + field + " | ge: " + ge + " | i :" + i);
        }
        //---------------------------------------------
    }

    data.list = [];
    while (gr._next()) {
        var record = {};
        $sp.getRecordElements(record, gr, data.fields);
        //if (gr instanceof FilteredGlideRecord) {  //From Global. KTorres
        // FilteredGlideRecord doesn't do field-level
        // security, so take care of that here
        for (var f in data.fields_array) {
            var fld = data.fields_array[f];
            if (!gr.isValidField(fld))
                continue;

            if (!gr[fld].canRead()) {
                record[fld].value = null;
                record[fld].display_value = null;
            }
        }
        //} //From Global 
        record.sys_id = gr.getValue('sys_id');
        data.list.push(record);
    }



    var breadcrumbWidgetParams = {
        table: data.table,
        query: data.filter,
        enable_filter: data.enable_filter
    };
    data.filterBreadcrumbs = $sp.getWidget('widget-filter-breadcrumbs', breadcrumbWidgetParams);

    // copy to data from input or options
    function optCopy(names) {
        names.forEach(function(name) {
            data[name] = input[name] || options[name];
        });
    }

})();
